AFTER:
private registerBinding(binding: ShortcutBinding): void {
  try {
    const success = this.registerFn(binding.accelerator, () => this.onAction(binding.action))
    if (!success) {
      this.reportError(new Error(`Failed to register shortcut: ${binding.accelerator}`))
    }
  } catch (err) {
    this.reportError(
      err instanceof Error ? err : new Error(`Failed to register shortcut: ${binding.accelerator}`, { cause: err })
    )
  }
}

registerAll(): void {
  if (this.registered) return
  for (const binding of this.bindings) {
    this.registerBinding(binding)
  }
  this.registered = true
}

WHY: Reduces nesting depth from 3 to 2 in both methods, makes the loop body trivially scannable, and isolates the error-handling logic for a single binding into its own testable unit.
